SELECT 
FROM jst_notice

    del_flag = '0'

        AND title LIKE CONCAT('%', #{title}, '%')


        AND category = #{category}


        AND status = #{status}


        AND top_flag = #{topFlag}


ORDER BY top_flag DESC, create_time DESC, notice_id DESC

SELECT FROM jst_notice WHERE del_flag = '0' AND status = 'published'
AND category = #{category}
ORDER BY top_flag DESC, publish_time DESC, notice_id DESC
